def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        temp_ratio = ratio
        for j in range(5):
            if temp_ratio < 0.05:
                score += (0.05 - temp_ratio) ** 3
            elif temp_ratio < 0.2:
                score += ((0.2 - temp_ratio) ** 2) * 0.7
            elif temp_ratio < 0.7:
                score += (0.7 - temp_ratio) * 0.4
            elif temp_ratio < 1:
                score += np.log1p(temp_ratio) * 0.5
            else:
                score += np.exp(temp_ratio - 1) * 0.2
            temp_ratio = temp_ratio ** 0.75 if j % 2 == 0 else np.sqrt(temp_ratio)
        if ratio < 0.3:
            for k in range(3):
                score += (0.3 - ratio) * 0.1 * (k + 1)
                if score > 2:
                    break
        elif ratio > 0.8:
            score += (ratio - 0.8) ** 2 * 3
        if capacity % 2 == 0:
            score *= 1.05
        else:
            score *= 0.95
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 0
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority + 2
    total = np.sum(priorities)
    if total > 0:
        priorities = priorities / total
    else:
        priorities = np.ones_like(priorities) / len(priorities)
    return priorities
